  /(?:may|june|july|aug|sep|oct|nov|dec|jan|feb|mar|apr).*?(20\d{2}).*?(?:series|raised|funding)/i
];
for (const pattern of fundingYearPatterns) {
  const match = allText.match(pattern);
  if (match) {
    const year = parseInt(match[1]);
    if (year >= 2015 && year <= currentYear && (!lastFundingYear || year > lastFundingYear)) {
      lastFundingYear = year;
    }
  }
}
if (lastFundingYear) {
  fundingAgeYears = currentYear - lastFundingYear;
}
const isStaleFunding = fundingAgeYears !== null && fundingAgeYears >= STALE_FUNDING_YEARS;

// v9.9: Graduated funding staleness modifier (Batch 4 Fix 4.2)
const isEarlyStage = ['Seed', 'Series A'].includes(fundingStage);
let fundingStalenessModifier = 0;
if (fundingAgeYears && isEarlyStage && (!employeeCount || employeeCount < 100)) {
  if (fundingAgeYears >= 4) fundingStalenessModifier = -15;
  else if (fundingAgeYears >= 3) fundingStalenessModifier = -10;
  else if (fundingAgeYears >= 2) fundingStalenessModifier = -5;
}

// v9.9: CX Tooling Company Detection (Batch 4 Fix 4.4)
let isCXToolingCompany = false;
let cxToolingSignals = [];
const allTextLower = allText.toLowerCase();

// v9.11: MERGER/REBRAND DETECTION (from pe-merger-detection-v1.1)
const mergerKeywords = [
