];
const hasMergerSignal = mergerKeywords.some(kw => allTextLower.includes(kw));

// v9.10: Expanded acquisition patterns with merger/rebrand
const mergerAcquirePatterns = [
  /acquired\s+by\s+([A-Z][a-zA-Z0-9&]+(?:\s+[A-Z]?[a-zA-Z0-9&]+)*)(?:\s+(?:in|for|from|,|\.)|$)/i,
  /bought\s+by\s+([A-Z][a-zA-Z0-9&]+(?:\s+[A-Z]?[a-zA-Z0-9&]+)*)(?:\s+(?:in|for|from|,|\.)|$)/i,
