  /bringing\s+together\s+([A-Z][a-zA-Z0-9&]+(?:\s+[A-Z]?[a-zA-Z0-9&]+)*)\s+(?:and|&|\+)/i,
  /formerly\s+known\s+as\s+([A-Z][a-zA-Z0-9&]+(?:\s+[A-Z]?[a-zA-Z0-9&]+)*)(?:\s|,|\.|$)/i,
