    /(?:powered|backed)\s+by\s+([A-Z][A-Za-z]+(?:\s+[A-Z]?[a-zA-Z]+)*)(?:[.,;:]|\s|$)/i
  ];
  for (const pattern of combinationPatterns) {
    const match = allText.match(pattern);
    if (match) {
      if (match[1]) predecessorNames.push(match[1].trim());
      if (match[2]) predecessorNames.push(match[2].trim());
      break;
    }
  }
  predecessorNames = [...new Set(predecessorNames)].map(n => n.replace(/\s+/g, ' ').trim()).filter(n => n.length > 2 && n.length < 60);
}

// v9.10: Generate merger DQ reason
let mergerDQReason = null;
if (hasMergerSignal && predecessorNames.length > 0 && !isPEBacked) {
  mergerDQReason = 'MERGER_DETECTED: Needs ownership verification (' + predecessorNames.join(' + ') + ')';
} else if (hasMergerSignal && !isPEBacked) {
  mergerDQReason = 'MERGER_DETECTED: Needs manual ownership verification';
}
for (const keyword of CX_TOOLING_KEYWORDS) { if (allTextLower.includes(keyword.toLowerCase())) { cxToolingSignals.push(keyword); } }
isCXToolingCompany = cxToolingSignals.length >= 2;

// v9.9: Suspicious employee count cross-reference (Batch 4 Fix 4.1)
const fundingStageRank = { 'Pre-Seed': 1, 'Seed': 2, 'Series A': 3, 'Series B': 4, 'Series C': 5, 'Series D': 6, 'Series E': 7 };
const isSeriesAPlus = fundingStage && fundingStageRank[fundingStage] >= 3;
const hasSignificantFunding = totalFunding && totalFunding >= 10000000;
