// === SECTOR DETECTION (v9.6 base + v9.7 additions) ===
const isBiotech = /\b(therapeutic|biologics|drug development|clinical trial|FDA approval|cell therapy|gene therapy|pharma|pharmaceutical|biotech|oncology|immunotherapy)\b/i.test(allText);
const isHardware = /\b(hardware|sensors|devices|robotics|manufacturing|chip|semiconductor|solar|battery|EV charging|physical product|wearable)\b/i.test(allText) && !/\b(SaaS|software platform|cloud platform|API)\b/i.test(allText);
