const isPhysicalSecurity = /\b(physical security|access control|surveillance|security camera|weapon detection|threat detection hardware|metal detector|security screening|visitor management hardware|perimeter security)\b/i.test(allText) && !/\b(cybersecurity|data security|cloud security)\b/i.test(allText);

