// Consumer Digital Health (patient-facing apps, not provider tools)
const isConsumerDigitalHealth = /\b(mental health app|therapy app|meditation app|wellness app|patient (?:portal|app|engagement)|health coaching app|symptom checker|self-care|digital therapeutic|DTx|behavioral health app|fertility app|pregnancy app|breastfeeding|lactation)\b/i.test(allText) && !/\b(provider-facing|clinician-facing|EHR|clinical workflow|healthcare operations)\b/i.test(allText);

