const isAICalling = /\b(AI (?:calling|phone|receptionist|voice agent)|automated (?:calling|phone calls)|voice AI (?:agent|assistant)|robocall|call automation|phone bot|AI answering)\b/i.test(allText) && !/\b(contact center|call center software|customer support platform)\b/i.test(allText);

// === v9.13: VC CATEGORY LABEL DETECTION ===
// VC scrapers include category tags in descriptions that existing sector patterns miss
const descAndEnrichment = ((companyData.description || '') + ' ' + allText).toLowerCase();

const isVCWaterTech = /\b(water tech|water treatment|water purification|irrigation tech)\b/i.test(descAndEnrichment);
const isVCLifeSci = /\b(life science|therapeutics company|gene therap|genomics company|biopharma company)\b/i.test(descAndEnrichment);
