// Climate tech: only DQ if NOT also a SaaS/software/analytics company
const climateLabelPattern = /\b(climate tech|clean energy|carbon tech|decarbonization|cleantech)\b/i;
const saasEscapePattern = /\b(SaaS|software platform|analytics|data platform|cloud platform)\b/i;
