const logisticsLabelPattern = /\b(freight|cargo platform|shipping platform|logistics company)\b/i;
const isVCLogisticsNonSaaS = logisticsLabelPattern.test(descAndEnrichment) && !saasEscapePattern.test(descAndEnrichment);

const isVCCategoryMismatch = isVCWaterTech || isVCClimateTechNonSaaS || isVCLifeSci || isVCNuclear || isVCLogisticsNonSaaS || isVCDTC || isVCInvestmentAI || isVCHeadlessCommerce;

// === v9.7: DEVELOPER-AS-CUSTOMER PERSONA GATE ===
const DEVELOPER_CUSTOMER_SIGNALS = [
  /\bfor developers\b/i,
  /\bdeveloper (?:platform|tools?|experience|workflow|productivity)\b/i,
  /\bAPI[- ]?first\b/i,
