  /\bdeveloper community\b/i,
  /\bdeveloper relations|devrel\b/i,
  /\bsoftware engineers? (?:use|love|trust|choose|rely)\b/i
];

// Counter-signals: enterprise sales motion selling TO developers (acceptable)
const ENTERPRISE_DEV_TOOL_SIGNALS = [
  /enterprise (?:developer|engineering) (?:platform|tools)/i,
  /\benterprise plan\b/i,
  /\bsales team\b.*\bdeveloper/i,
  /\baccount executive\b/i,
  /\benterprise customers?\b/i,
  /\bFortune (?:500|1000|100)\b/i,
  /\bsecurity compliance\b/i,
