  /\bSSO\b/i,
  /\baudit log\b/i
];

const devCustomerSignalCount = DEVELOPER_CUSTOMER_SIGNALS.filter(p => p.test(allText)).length;
const enterpriseDevSignalCount = ENTERPRISE_DEV_TOOL_SIGNALS.filter(p => p.test(allText)).length;
const isDeveloperCustomer = devCustomerSignalCount >= 2;
const hasEnterpriseSalesMotionForDevTool = enterpriseDevSignalCount >= 2;

// Gate logic: developer-as-customer is DQ if <50 employees AND no enterprise sales motion
// If 50+ employees with enterprise motion, it passes (gets evaluated with domain distance penalty)
const isDeveloperCustomerDQ = isDeveloperCustomer && !hasEnterpriseSalesMotionForDevTool && (!employeeCount || employeeCount < 50);

// Combine all non-B2B-SaaS flags (v9.13: added VC category labels)
const isNotB2BSaaS = isBiotech || isHardware || isCrypto || isConsumer || isHRTech || isClimateHardware || isAgTech || isMarketplace || isIoT || isMaterials || isHealthcareCareDelivery || isMedicalDevice || isCybersecurity || isLegalTech || isEdTech || isPropertyManagement || isTaxTech || isSalesTools || isVeterinary || isFintech || isConstructionTech || isFoodBiotech || isPhysicalSecurity || isInsurtech || isSaaSManagement || isConsumerDigitalHealth || isAICalling || isVCCategoryMismatch;

// v9.13: Explicit business model classification
let businessModelClass = 'UNKNOWN';
if (isNotB2BSaaS) {
  if (isBiotech || isVCLifeSci) businessModelClass = 'MEDTECH_LIFESCI';
  else if (isHardware || isClimateHardware || isVCWaterTech || isVCNuclear) businessModelClass = 'HARDWARE_DEEPTECH';
  else if (isConsumer || isVCDTC) businessModelClass = 'B2C_DTC';
  else if (isMarketplace) businessModelClass = 'MARKETPLACE';
  else if (isHealthcareCareDelivery) businessModelClass = 'CARE_DELIVERY';
  else if (isFintech || isInsurtech || isVCInvestmentAI) businessModelClass = 'FINTECH';
  else if (isMedicalDevice) businessModelClass = 'MEDICAL_DEVICE';
  else if (isAgTech || isMaterials || isIoT) businessModelClass = 'INDUSTRIAL';
  else if (isCrypto) businessModelClass = 'CRYPTO';
  else if (isVCClimateTechNonSaaS) businessModelClass = 'CLIMATE_HARDWARE';
  else if (isVCLogisticsNonSaaS) businessModelClass = 'LOGISTICS';
  else if (isVCHeadlessCommerce) businessModelClass = 'ECOMMERCE';
  else businessModelClass = 'OTHER_NON_SAAS';
} else if (!isSoftwareFirst) {
  businessModelClass = 'SERVICES';
} else if (isPLGDominant) {
  businessModelClass = 'B2B_SAAS_PLG';
} else if (hasEnterpriseMotion) {
  businessModelClass = 'B2B_SAAS_ENTERPRISE';
} else {
  businessModelClass = 'B2B_SAAS';
}

// === BUILD DISQUALIFICATION LIST ===
const autoDisqualifiers = [];

// TIER 1: HARD GATES
if (!isValidEntity) autoDisqualifiers.push(entityValidationReason || 'Invalid entity (media/podcast/nonprofit)');
if (isAcquired) autoDisqualifiers.push(`Acquired${acquiredBy ? ' by ' + acquiredBy : ''}${acquiredByPE ? ' (PE)' : ''}`);
if (isPEBacked) autoDisqualifiers.push(`PE-backed (${peBackerFound})`);
if (mergerDQReason) autoDisqualifiers.push(mergerDQReason);
if (isFortune500Subsidiary) autoDisqualifiers.push(`Fortune 500 subsidiary${fortune500Parent ? ' (' + fortune500Parent + ')' : ''}`);
if (isKnownLargeCompany) autoDisqualifiers.push('Known large company (enrichment bypass)');
if (employeeCount && employeeCount > HARD_EMPLOYEE_CAP) autoDisqualifiers.push(`Too large (>${HARD_EMPLOYEE_CAP} employees: ${employeeCount})`);
