  else if (isAICalling) autoDisqualifiers.push('AI calling/voice agent (not enterprise CS)');
  // v9.13: VC category label gates
  else if (isVCWaterTech) autoDisqualifiers.push('VC category: water tech (not B2B SaaS)');
  else if (isVCClimateTechNonSaaS) autoDisqualifiers.push('VC category: climate tech (non-SaaS)');
