// v8.5: SCORING FIXES - employee-user persona, 3+ enterprise signals
const response = $json;

// Build Map of company data by ref for O(1) lookup
const promptItems = $('Build Persona Prompt').all();
const companyByRef = new Map();
for (const item of promptItems) {
  const ref = item.json._companyRef || item.json._updateRecordId || item.json.company_name;
  if (ref) companyByRef.set(ref, item.json);
}

const currentIndex = $itemIndex;
let companyData = promptItems[currentIndex]?.json || {};

// Enterprise motion signals that indicate a developer/employee-user tool might still be a fit
const enterpriseSignals = [
  /\bSOC\s*2\b/i,
  /\bHIPAA\b/i,
  /\bcompliance\b/i,
  /\benterprise\s*(customers?|clients?|plan|pricing|tier|sales)/i,
  /\bFortune\s*500\b/i,
  /\bFortune\s*1000\b/i,
  /\bsales\s*team\b/i,
  /\baccount\s*executives?\b/i,
  /\bSSO\b/i,
  /\bSAML\b/i,
  /\bmulti-tenant\b/i,
  /\bself-hosted\b/i,
  /\bon-prem(ise)?\b/i,
  /\bcontract\s*value\b/i,
  /\bACV\b/i,
  /\bARR\b/i,
  /\bsecurity\s*review\b/i,
  /\bprocurement\b/i,
  /\bvendor\s*management\b/i
];

// Parse persona from Claude response
let persona = 'unknown';
try {
  const content = response.content?.[0]?.text || '';
  const cleanContent = content.toLowerCase().trim();
  // v8.5: Check employee-user BEFORE business-user (it contains 'user')
  if (cleanContent.includes('employee-user') || cleanContent === 'employee-user') {
    persona = 'employee-user';
  } else if (cleanContent.includes('business-user') || cleanContent === 'business-user') {
    persona = 'business-user';
  } else if (cleanContent.includes('developer') || cleanContent === 'developer') {
    persona = 'developer';
  } else if (cleanContent.includes('mixed') || cleanContent === 'mixed') {
    persona = 'mixed';
  }
} catch (e) {
  persona = 'unknown';
}

// Check enterprise signals in the description
const description = companyData.description || '';
const matchedSignals = enterpriseSignals.filter(pattern => pattern.test(description));
const enterpriseSignalCount = matchedSignals.length;

const employeeCount = companyData.employee_count || 0;

// v8.5: Both developer AND employee-user get auto-pass treatment
// B2B2C (employee-user) doesn't need traditional CS leadership
const isDeveloperTool = persona === 'developer';
const isEmployeeUser = persona === 'employee-user';
const needsAutoPassCheck = isDeveloperTool || isEmployeeUser;

// v8.5 FIX: Require 3+ enterprise signals (stricter than 2+)
const ENTERPRISE_SIGNAL_THRESHOLD = 3;
const hasEnterpriseException = needsAutoPassCheck && employeeCount >= 50 && enterpriseSignalCount >= ENTERPRISE_SIGNAL_THRESHOLD;

// Auto-pass decision:
// - Developer/employee-user + <50 employees → auto-pass
// - Developer/employee-user + 50+ employees but <3 enterprise signals → auto-pass
// - Developer/employee-user + 50+ employees + 3+ enterprise signals → proceed (exception)
// - Business-user or mixed → proceed
const shouldAutoPass = needsAutoPassCheck && !hasEnterpriseException;

let autoPassReason = null;
if (shouldAutoPass) {
  const personaLabel = isEmployeeUser ? 'B2B2C (employee-user)' : 'Developer-as-customer';
  if (employeeCount < 50) {
    autoPassReason = `${personaLabel} (${employeeCount || 'unknown'} employees) - not at enterprise scale`;
  } else {
    autoPassReason = `${personaLabel} with ${employeeCount} employees but only ${enterpriseSignalCount} enterprise signals (need ${ENTERPRISE_SIGNAL_THRESHOLD}+)`;
  }
}

const { _personaPrompt, ...cleanData } = companyData;

return {
  json: {
    ...cleanData,
    customer_persona: persona,
    enterprise_signal_count: enterpriseSignalCount,
    has_enterprise_exception: hasEnterpriseException,
    developer_auto_pass: shouldAutoPass,
    developer_auto_pass_reason: autoPassReason,
    _personaItemIndex: currentIndex
  }
};

