// v9.13: Parse Evaluation with bucket enforcement fix and default score detection
// v9.9: Batch 4 CS Hire Readiness score capping
const response = $json;
const companyItems = $('Build Evaluation Prompt').all();

const companyByRef = new Map();
for (const item of companyItems) {
  const ref = item.json._companyRef || item.json._updateRecordId || item.json.company_name;
  if (ref) companyByRef.set(ref, item.json);
}

let evaluation = {};
try {
  const content = response.content?.[0]?.text || '';
  const jsonMatch = content.match(/\{[\s\S]*\}/);
  if (jsonMatch) evaluation = JSON.parse(jsonMatch[0]);
} catch (e) {
  evaluation = { bucket: 'WATCH', total_score: 0, summary: 'Parse error - manual review needed' };
}

const refFromClaude = evaluation.company_ref || '';
let companyData = companyByRef.get(refFromClaude);
let refMatchType = 'exact';

if (!companyData) {
  const currentIndex = $itemIndex;
  companyData = companyItems[currentIndex]?.json || {};
  refMatchType = 'fallback';
}

// v9.9: CS Hire Readiness Score Capping (Batch 4 Fix 4.3)
let finalScore = evaluation.total_score || 0;
const originalScore = finalScore;
let scoreCapped = false;
let scoreCapReason = null;

const csHireLikelihood = (evaluation.cs_hire_likelihood || '').toLowerCase();

// Graduated caps: unlikely=65, low=75 (Opus review improvement)
if (csHireLikelihood === 'unlikely') {
  if (finalScore > 65) {
    scoreCapped = true;
    scoreCapReason = 'Score capped from ' + finalScore + ' to 65: CS hire likelihood is unlikely';
    finalScore = 65;
  }
} else if (csHireLikelihood === 'low') {
  if (finalScore > 75) {
    scoreCapped = true;
    scoreCapReason = 'Score capped from ' + finalScore + ' to 75: CS hire likelihood is low';
    finalScore = 75;
  }
}

// v9.9: Apply funding staleness modifier from enrichment
const fundingStalenessModifier = companyData.funding_staleness_modifier || 0;
if (fundingStalenessModifier < 0) {
  const beforeMod = finalScore;
  finalScore = Math.max(0, finalScore + fundingStalenessModifier);
  const modNote = 'Funding staleness: ' + fundingStalenessModifier + ' (from ' + beforeMod + ' to ' + finalScore + ')';
  scoreCapReason = scoreCapReason ? scoreCapReason + ' | ' + modNote : modNote;
}

// v9.13: ALWAYS enforce threshold -- never trust Claude's bucket
let bucket;
if (finalScore >= 70) bucket = 'APPLY';
else if (finalScore >= 40) bucket = 'WATCH';
else bucket = 'PASS';

// Log when Claude disagrees (useful for prompt calibration)
const claudeBucket = evaluation.bucket || 'unknown';
const bucketOverridden = (claudeBucket.toUpperCase() !== bucket);
if (bucketOverridden) {
  scoreCapReason = (scoreCapReason ? scoreCapReason + ' | ' : '') +
    'Bucket override: Claude said ' + claudeBucket + ' at score ' + finalScore + ', enforced ' + bucket;
}

// v9.13: Default score detection (safety net)
const csReadinessFromEval = evaluation.scores?.cs_hire_readiness || 0;
const isLikelyDefaultScore = (
  (finalScore >= 55 && finalScore <= 65) &&
  (csReadinessFromEval <= 10) &&
  (csHireLikelihood === '' || csHireLikelihood === 'low' || csHireLikelihood === 'unlikely')
);
if (isLikelyDefaultScore) {
  const beforeFloor = finalScore;
  finalScore = Math.min(finalScore, 30);
  bucket = 'PASS';
  scoreCapReason = (scoreCapReason ? scoreCapReason + ' | ' : '') +
    'Default score detected (' + beforeFloor + ' with cs_readiness=' + csReadinessFromEval +
    ', likelihood=' + csHireLikelihood + '). Safety-capped to ' + finalScore;
}

const statusMap = { 'APPLY': 'Apply', 'WATCH': 'Monitor', 'PASS': 'Passed' };

return {
  json: {
    _updateRecordId: companyData._updateRecordId || null,
    _dedupKey: companyData._dedupKey,
    company_name: companyData.company_name,
    company_url: companyData.company_url,
    description: companyData.description,
    source: companyData.source,
    status: statusMap[bucket] || 'Research',

    total_score: finalScore,
    original_score: scoreCapped ? originalScore : null,
    score_capped: scoreCapped,
    score_cap_reason: scoreCapReason || '',
    base_score: evaluation.base_score || evaluation.total_score || 0,
    sector_match: evaluation.sector_match || 'unknown',
    domain_distance: evaluation.domain_distance || 'unknown',
    domain_distance_modifier: evaluation.scores?.domain_distance_modifier || 0,
    gtm_motion: evaluation.gtm_motion || companyData.gtm_motion || 'unknown',
    cs_hire_likelihood: evaluation.cs_hire_likelihood || '',
    product_type: evaluation.product_type || '',
    role_type: evaluation.role_type || 'unknown',
    summary: (scoreCapped ? '[CAPPED] ' : '') + (evaluation.summary || ''),
    funding_stage: companyData.funding_stage,
    total_funding: companyData.total_funding,
    employee_count: companyData.employee_count,
    pe_backed: companyData.pe_backed,
    founded_year: companyData.founded_year,
    customer_persona: companyData.customer_persona || 'unknown',
    cs_readiness_score: companyData.cs_readiness_score || null,
    stale_funding_flag: evaluation.stale_funding_flag || false,
    // v9.9: Batch 4 fields
    is_cx_tooling_company: companyData.is_cx_tooling_company || false,
    cx_tooling_signals: companyData.cx_tooling_signals || '',
    suspicious_employee_count: companyData.suspicious_employee_count || false,
    employee_count_flag: companyData.employee_count_flag || '',
    funding_staleness_modifier: fundingStalenessModifier,
    _refMatch: refMatchType,
    _evalItemIndex: $itemIndex
  }
};

// OPTIMIZED: Check job matches and LinkedIn connections using Map lookups
// v8.4.1: Added try/catch for node references to handle execution timing issues
let evalItems = [];
let jobListings = [];
let linkedInConnections = [];

try {
  evalItems = $('Parse Evaluation').all();
} catch(e) {
  // Parse Evaluation should always exist if we got here
  evalItems = [];
}

try {
  jobListings = $('Search Job Listings').all();
} catch(e) {
  // Job Listings search may not have completed - continue with empty array
  jobListings = [];
}

try {
  linkedInConnections = $('Search LinkedIn Connections').all();
} catch(e) {
  // LinkedIn search may not have completed - continue with empty array
  linkedInConnections = [];
}

// If no eval items, return empty result
if (evalItems.length === 0) {
  return [{ json: { _error: true, _message: 'No evaluation items available' } }];
}

const normalize = (str) => str ? String(str).toLowerCase().replace(/[^a-z0-9]/g, '').trim() : '';

// Build a Map for O(1) job lookups
const jobsByCompany = new Map();
for (const job of jobListings) {
  const fields = job.json.fields || job.json;
  const company = normalize(fields['Company'] || fields['company'] || '');
  if (!company) continue;
  if (!jobsByCompany.has(company)) jobsByCompany.set(company, []);
  jobsByCompany.get(company).push(job);
}

// Build a Map for O(1) LinkedIn connection lookups
const connectionsByCompany = new Map();
for (const conn of linkedInConnections) {
  const fields = conn.json.fields || conn.json;
  // Use pre-computed normalized field if available, otherwise normalize
  const company = fields['Company Normalized'] || normalize(fields['Company'] || '');
  if (!company) continue;
  if (!connectionsByCompany.has(company)) connectionsByCompany.set(company, []);
  connectionsByCompany.get(company).push({
    name: fields['Name'] || '',
    position: fields['Position'] || '',
    linkedInUrl: fields['LinkedIn URL'] || ''
  });
}

const cxKeywords = ['customer', 'support', 'success', 'cx', 'experience', 'service', 'care', 'advocate', 'onboarding', 'implementation'];
const activeStatuses = ['new', 'reviewing', 'applied', 'interviewing', 'phone screen', 'on-site', 'offer'];

return evalItems.map(evalItem => {
  const companyName = evalItem.json.company_name || '';
  const normalizedCompany = normalize(companyName);

  // Check job matches
  const matchingJobs = jobsByCompany.get(normalizedCompany) || [];
  const activeJobs = matchingJobs.filter(job => {
    const fields = job.json.fields || job.json;
    const status = (fields['Review Status'] || '').toLowerCase();
    return activeStatuses.includes(status);
  });
  const cxJobs = activeJobs.filter(job => {
    const fields = job.json.fields || job.json;
    const title = (fields['Job Title'] || '').toLowerCase();
    return cxKeywords.some(kw => title.includes(kw));
  });

  // Check LinkedIn connections
  const matchingConnections = connectionsByCompany.get(normalizedCompany) || [];
  const hasNetworkConnection = matchingConnections.length > 0;
  const connectionNames = matchingConnections.map(c => `${c.name} (${c.position})`).join(', ');
  const connectionLinkedInUrl = matchingConnections.length > 0 ? matchingConnections[0].linkedInUrl : '';

  return {
    json: {
      ...evalItem.json,
      // Preserve customer_persona
      customer_persona: evalItem.json.customer_persona || 'unknown',
      // Job matching fields
      hasActiveJobPosting: activeJobs.length > 0,
      hasCxJobPosting: cxJobs.length > 0,
      matchingJobCount: activeJobs.length,
      matchingCxJobCount: cxJobs.length,
      matchingJobTitles: activeJobs.map(j => (j.json.fields || j.json)['Job Title'] || '').filter(Boolean).join(', '),
      matchingJobIds: activeJobs.map(j => j.json.id).filter(Boolean),
      // LinkedIn connection fields
      hasNetworkConnection: hasNetworkConnection,
      connectionName: connectionNames,
      connectionLinkedInUrl: connectionLinkedInUrl,
      connectionCount: matchingConnections.length
    }
  };
});

